    links:[["Boulder County Sheriff, UPDATE: Death Investigation Near Ridge Road","https://bouldercounty.gov/news/update-death-investigation-near-ridge-road/"],["Fox News, UFO writer / paranormal YouTuber dies suicide / mental health call to police","https://www.foxnews.com/us/ufo-writer-paranormal-youtuber-dies-suicide-home-mental-health-call-police"],["Daily Mail, David Wilcock UFO researcher Colorado death","https://www.dailymail.com/sciencetech/article-15760239/david-wilcock-ufo-researcher-colorado-death.html"],["Mashable, Community claim biographer Wynn Free died two days before","https://in.mashable.com/culture/108821/david-wicocks-death-community-claim-his-biographer-wynn-free-died-two-days-before-ufo-authors-allege"],["Hindustan Times, 'Weird twist' Jay Weidner claim on Wynn Free","https://www.hindustantimes.com/world-news/us-news/did-david-wilcocks-biographer-die-2-days-before-ufo-experts-alleged-suicide-weird-twist-emerges-amid-rumors-101776840848456.html"]],
